INSERT INTO "public"."articles" ("id", "title", "content", "category", "sub_category", "created_at", "updated_at", "image_url", "slug", "blocks", "section") VALUES ('057a1602-1691-43f5-9696-a417eabc2f02', 'トレードで大事なこと', '自分の力で財を成した人は社会の役に立ってお金持ちになった
                失敗しても執念を燃やして粘り強く努力を重ねる起業家
                お金持ちになるための条件の一つは強い精神力を持つこと
                どんな問題でもその多くを解決することができる
