                成功者との付き合いが自分に好ましい影響を与え、資産を築くうえで不可欠な要素となったことに気づくはず
', 'mind', 'トレードで大事なこと', '2024-12-29 19:29:58.409093+00', '2024-12-29 19:29:58.409093+00', '', 'important-in-trade', null, null), ('05b4fb1a-91a1-4758-b779-c0cdc5e162c4', '平均足システム', '平均足システム', 'system', 'EA4(平均足システム・NY_Box)', '2025-01-04 20:31:16.685321+00', '2025-01-04 20:31:16.685321+00', '', '-14', '[{"type":"code","content":"// マジックナンバーの定義\\n#define MAGIC 1192\\n\\n// パラメーターの設定//\\nextern double Lots = 1.0; // 取引ロット数\\nextern int Slip = 10; // 許容スリッページ数\\nextern string Comments = \\" \\"; // コメント\\n\\n// 変数の設定//\\nint Ticket_L = 0; // 買い注文の結果をキャッチする変数\\nint Ticket_S = 0; // 売り注文の結果をキャッチする変数\\nint Exit_L = 0; // 買いポジションの決済注文の結果をキャッチする変数\\nint Exit_S = 0; // 売りポジションの決済注文の結果をキャッチする変数\\n\\ndouble Heiken_Open_2 = 0; /*2 本前のバーの平均足の始値に変身した　　\\n　　　　　　　　　　　　　 iCustom 関数を代入する変数*/\\ndouble Heiken_Close_2 = 0; /*2 本前のバーの平均足の終値に変身した\\n　　　　　　　　　　　　　 iCustom 関数を代入する変数*/\\ndouble Heiken_Open_1 = 0; /*1 本前のバーの平均足の始値に変身した\\n　　　　　　　　　　　　　iCustom 関数を代入する変数*/\\ndouble Heiken_Close_1 = 0; /*1 本前のバーの平均足の終値に変身した\\n                          iCustom 関数を代入する変数*/\\n\\n\\nint start()\\n{\\n\\n   Heiken_Open_2 = iCustom(NULL,0,\\"Heiken Ashi\\",0,2);\\n   Heiken_Close_2 = iCustom(NULL,0,\\"Heiken Ashi\\",3,2);\\n   Heiken_Open_1 = iCustom(NULL,0,\\"Heiken Ashi\\",0,1);\\n   Heiken_Close_1 = iCustom(NULL,0,\\"Heiken Ashi\\",3,1);\\n   \\n   // 買いポジションのエグジット\\n   if(   Heiken_Open_2 <= Heiken_Close_2\\n      && Heiken_Open_1 > Heiken_Close_1\\n      && ( Ticket_L != 0 && Ticket_L != -1 ))\\n      {\\n         Exit_L = OrderClose(Ticket_L,Lots,Bid,Slip,Red);\\n         if( Exit_L ==1 ) {Ticket_L = 0;}\\n      }\\n      \\n   // 売りポジションのエグジット\\n   if(   Heiken_Open_2 >= Heiken_Close_2\\n      && Heiken_Open_1 < Heiken_Close_1\\n      && ( Ticket_S != 0 && Ticket_S != -1 ))\\n      {\\n         Exit_S = OrderClose(Ticket_S,Lots,Ask,Slip,Blue);\\n         if( Exit_S ==1 ) {Ticket_S = 0;}\\n      }\\n      \\n   // 買いエントリー\\n   if(   Heiken_Open_2 >= Heiken_Close_2\\n      && Heiken_Open_1 < Heiken_Close_1\\n      && ( Ticket_L == 0 || Ticket_L == -1 )\\n      && ( Ticket_S == 0 || Ticket_S == -1 ))\\n      {\\n         Ticket_L = OrderSend(Symbol(),OP_BUY,Lots,Ask,Slip,0,0,Comments,MAGIC,0,Red);\\n      }\\n      \\n   // 売りエントリー\\n   if(   Heiken_Open_2 <= Heiken_Close_2\\n      && Heiken_Open_1 > Heiken_Close_1\\n      && ( Ticket_S == 0 || Ticket_S == -1 )\\n      && ( Ticket_L == 0 || Ticket_L == -1 ))\\n      {\\n         Ticket_S = OrderSend(Symbol(),OP_SELL,Lots,Bid,Slip,0,0,Comments,MAGIC,0,Blue);\\n      }\\n      \\nreturn(0);\\n}","metadata":{"language":"cpp"}}]', null), ('0f31a09f-2f89-4100-8f47-880a24646dfb', '一目均衡表システム（遅行スパン編）', '一目', 'system', 'EA2(一目均衡表システム)', '2025-01-04 20:16:48.678568+00', '2025-01-04 20:25:47.473+00', '', '-12', '[{"type":"code","content":" // マジックナンバーの定義\\n #define MAGIC 1919\\n \\n // パラメーターの設定//\\n extern int Tenkan = 6; // 転換線の期間設定\\n extern int Kijun = 26; // 基準線の期間設定\\n extern int Senkou = 52; // 先行線の期間設定\\n \\n extern double Lots = 1.0; // 取引ロット数\\n extern int Slip = 10; // 許容スリッページ数\\n extern string Comments = \\" \\"; // コメント\\n \\n // 変数の設定//\\n int Ticket_L = 0; // 買い注文の結果をキャッチする変数\\n int Ticket_S = 0; // 売り注文の結果をキャッチする変数\\n int Exit_L = 0; // 買いポジションの決済注文の結果をキャッチする変数\\n int Exit_S = 0; // 売りポジションの決済注文の結果をキャッチする変数\\n \\n double Chikou_2 = 0; /*Kijun+2 本前のバーの遅行スパンに変身した\\n                      iCustom 関数を代入する変数*/\\n double Chikou_1 = 0; /*Kijun+1 本前のバーの遅行スパンに変身した\\n                      iCustom 関数を代入する変数*/\\n \\n int start()\\n {\\n \\n    Chikou_2 = iCustom(NULL,0,\\"Ichimoku\\",Tenkan,Kijun,Senkou,4,Kijun+2);\\n    Chikou_1 = iCustom(NULL,0,\\"Ichimoku\\",Tenkan,Kijun,Senkou,4,Kijun+1);\\n    \\n    // 買いポジションのエグジット\\n    if(   Chikou_2 >= Close[Kijun+2]\\n       && Chikou_1 < Close[Kijun+1]\\n       && ( Ticket_L != 0 && Ticket_L != -1 ))\\n       {\\n          Exit_L = OrderClose(Ticket_L,Lots,Bid,Slip,Red);\\n          if( Exit_L == 1 ) {Ticket_L = 0;}\\n       }\\n       \\n    // 売りポジションのエグジット\\n    if(   Chikou_2 <= Close[Kijun+2]\\n       && Chikou_1 > Close[Kijun+1]\\n       && ( Ticket_S != 0 && Ticket_S != -1 ))\\n       {\\n          Exit_S = OrderClose(Ticket_S,Lots,Ask,Slip,Blue);\\n          if( Exit_S == 1 ) {Ticket_S = 0;}\\n       }\\n       \\n    // 買いエントリー\\n    if(   Chikou_2 <= Close[Kijun+2]\\n       && Chikou_1 > Close[Kijun+1]\\n       && ( Ticket_L == 0 || Ticket_L == -1 )\\n       && ( Ticket_S == 0 || Ticket_S == -1 ))\\n       {\\n          Ticket_L = OrderSend(Symbol(),OP_BUY,Lots,Ask,Slip,0,0,Comments,MAGIC,0,Red);\\n       }\\n       \\n    // 売りエントリー\\n    if(   Chikou_2 >= Close[Kijun+2]\\n       && Chikou_1 < Close[Kijun+1]\\n       && ( Ticket_S == 0 || Ticket_S == -1 )\\n       && ( Ticket_L == 0 || Ticket_L == -1 ))\\n       {\\n          Ticket_S = OrderSend(Symbol(),OP_SELL,Lots,Bid,Slip,0,0,Comments,MAGIC,0,Blue);\\n       }\\n    \\n return(0);\\n }","metadata":{"language":"cpp"}}]', null), ('22975628-9e2e-4d58-9eaf-1b148c447c9c', 'fdf', '                        EdtechとはEducationのEdとTechnologyのTechを組み合わせた造語でオンライン教育だけでなくAIやVR/ARなどのデジタル技術を活用した様々な学習ツールやサービスを指す

', 'stock', '株式投資とは', '2025-01-11 03:51:18.365964+00', '2025-01-11 03:51:18.365964+00', '', 'stock-detail', '[{"type":"text","content":""}]', 'invester'), ('278ac02a-4bf4-47bc-b8b3-9aab7bbc0790', '準備', '準備', 'fx', 'MT4の準備', '2025-01-05 00:03:05.459347+00', '2025-01-05 00:03:05.459347+00', '', 'fx-start', '[{"type":"text","content":""}]', null), ('288a5d25-0103-41f1-81dd-af365202201e', 'fdd', 'fdd', 'system', 'EA7(定型文)', '2025-01-04 20:41:22.074348+00', '2025-01-04 20:41:22.074348+00', '', 'fdd', '[{"type":"code","content":"//マジックナンバーの定義\\n#define MAGIC  4649        \\n\\n//パラメーターの設定//\\nextern double Lots = 1.0;     //取引ロット数\\nextern int Slip = 10;         //許容スリッページ数\\nextern string Comments =  \\"\\"; //コメント\\n\\n//変数の設定//\\nint Ticket_L = 0; //買い注文の結果をキャッチする変数\\nint Ticket_S = 0; //売り注文の結果をキャッチする変数\\nint Exit_L = 0;   //買いポジションの決済注文の結果をキャッチする変数\\nint Exit_S = 0;   //売りポジションの決済注文の結果をキャッチする変数\\n\\n\\nint start()\\n  {\\n     \\n   //買いポジションのエグジット\\n   if(    ■■■■\\n       && ( Ticket_L != 0 && Ticket_L != -1 ))\\n    {     \\n      Exit_L = OrderClose(Ticket_L,Lots,Bid,Slip,Red);\\n      if( Exit_L ==1 ) {Ticket_L = 0;}\\n    }    \\n    \\n   //売りポジションのエグジット\\n   if(    □□□□\\n       && ( Ticket_S != 0 && Ticket_S != -1 ))\\n    {     \\n      Exit_S = OrderClose(Ticket_S,Lots,Ask,Slip,Blue);\\n      if( Exit_S ==1 ) {Ticket_S = 0;} \\n    }   \\n    \\n   //買いエントリー\\n   if(    ▲▲▲▲\\n       && ( Ticket_L == 0 || Ticket_L == -1 ) \\n       && ( Ticket_S == 0 || Ticket_S == -1 ))\\n    {  \\n      Ticket_L = OrderSend(Symbol(),OP_BUY,Lots,Ask,Slip,0,0,Comments,MAGIC,0,Red);\\n    }\\n    \\n   //売りエントリー\\n   if(    △△△△\\n       && ( Ticket_S == 0 || Ticket_S == -1 )\\n       && ( Ticket_L == 0 || Ticket_L == -1 ))\\n    {   \\n      Ticket_S = OrderSend(Symbol(),OP_SELL,Lots,Bid,Slip,0,0,Comments,MAGIC,0,Blue);     \\n    } \\n    \\n     \\n   return(0);\\n  }\\n\\n\\n","metadata":{"language":"cpp"}}]', null), ('28b707de-0f45-4c6d-9969-bb742151b7f3', '金', '金を買った方が良い1つ目の理由は強烈なクラッシュが起きたときに資産を守る保険になるからです
