', 'mind', '資金管理とリスクリワード', '2024-12-30 03:27:49.032914+00', '2024-12-30 03:27:49.032914+00', '', '-7', '[{"type":"text","content":""}]', null), ('5cef2655-989d-4d23-955e-c8cee06c71d5', 'NY_Box', 'NY_Box', 'system', 'EA4(平均足システム・NY_Box)', '2025-01-04 20:32:59.14744+00', '2025-01-04 20:32:59.14744+00', '', 'ny-box', '[{"type":"code","content":" //+------------------------------------------------------------------+\\n//|                                                       NY_Box.mq4 |\\n//|                                                                  |\\n//|                                                                  |\\n//+------------------------------------------------------------------+\\n#property indicator_chart_window\\n#property indicator_buffers 2\\n#property indicator_color1 Red\\n#property indicator_color2 Blue\\n\\nextern int Start_Hour =10;\\nextern int End_Hour   =17;\\n\\n//指標バッファ\\ndouble Buf0[];\\ndouble Buf1[];\\n\\ndouble HH  = 0;\\ndouble LL  = 999999;\\n\\n\\n//+------------------------------------------------------------------+\\n//| Custom indicator initialization function                         |\\n//+------------------------------------------------------------------+\\n\\nint init()\\n{\\n \\n   SetIndexBuffer(0,Buf0);\\n   SetIndexBuffer(1,Buf1);\\n   SetIndexLabel(0,\\"HighestHigh\\");\\n   SetIndexLabel(1,\\"LowestLow\\");\\n\\n   return(0);\\n}\\n\\n//+------------------------------------------------------------------+\\n//| Custom indicator iteration function                              |\\n//+------------------------------------------------------------------+\\n\\nint start()\\n{\\n   \\n   int limit = Bars-IndicatorCounted();\\n   if(limit==1) return(0);\\n \\n   for(int i=limit-2; i>=0; i--)\\n    {        \\n      if(    (Start_Hour <  End_Hour &&  TimeHour(iTime(NULL,0,i+1)) >= Start_Hour && TimeHour(iTime(NULL,0,i+1)) < End_Hour )\\n          || (Start_Hour >  End_Hour && (TimeHour(iTime(NULL,0,i+1)) >= Start_Hour || TimeHour(iTime(NULL,0,i+1)) < End_Hour )) \\n          ||  Start_Hour == End_Hour )\\n       {         \\n         if( HH < High[i+1] )\\n          {\\n            HH = High[i+1];             \\n          }\\n                     \\n         if( LL > Low[i+1] )\\n          {\\n            LL = Low[i+1];             \\n          }\\n       }\\n       \\n        \\n      if( TimeHour(iTime(NULL,0,i+1)) != End_Hour && TimeHour(iTime(NULL,0,i)) == End_Hour )\\n       {\\n         Buf0[i] = HH; \\n         Buf1[i] = LL; \\n         HH = 0;\\n         LL = 999999; \\n       }  \\n      else\\n       {\\n         Buf0[i]= Buf0[i+1]; \\n         Buf1[i]= Buf1[i+1];      \\n       }\\n       \\n   }\\n\\n   return(0);\\n}\\n//+----------------------------","metadata":{"language":"cpp"}}]', null), ('64085a1b-2470-4880-8234-8a40c1c12117', 'di', '<div className='text-2xl text-center m-4 border-b-4 border-blue-400'>トークノミクスこそがWeb3の革命</div>



