習得型の目標は短期的な成果よりもどれだけ進歩し、成長したかなどの長期的な成果を重視する。難しい局面に直面してもモチベーションが落ち込みにくくなる。
', 'mind', '勝つための準備', '2024-12-29 19:02:00.616706+00', '2024-12-29 19:02:00.616706+00', '', 'preparing-to-win', null, null), ('9496022d-c42b-41a6-9d37-d7d62b46a984', 'MA', 'MA', 'system', 'EA1(MACD・Moving Average)', '2025-01-04 20:13:31.361127+00', '2025-01-04 20:13:31.361127+00', '', 'ma', '[{"type":"code","content":"//+------------------------------------------------------------------+\\n//|                                               Moving Average.mq4 |\\n//|                   Copyright 2005-2014, MetaQuotes Software Corp. |\\n//|                                              http://www.mql4.com |\\n//+------------------------------------------------------------------+\\n#property copyright   \\"2005-2014, MetaQuotes Software Corp.\\"\\n#property link        \\"http://www.mql4.com\\"\\n#property description \\"移動平均線EA\\"\\n#property description \\"日本語翻訳-最大ポジション保有数は1つ\\"\\n\\n//--- 定数のマジックナンバー\\n#define MAGICMA  20131111\\n\\n//--- 入力変数（外部変数）\\n//--- ロット数\\ninput double Lots          =0.1;\\n//--- リスクロット調整（％）\\ninput double MaximumRisk   =0.02;\\n//--- ロット減少調整数値\\ninput double DecreaseFactor=3;\\n//--- 移動平均線の期間\\ninput int    MovingPeriod  =12;\\n//--- 移動平均線のシフト\\ninput int    MovingShift   =6;\\n//+------------------------------------------------------------------+\\n//| 保有中のポジションの計算                                              |\\n//+------------------------------------------------------------------+\\nint CalculateCurrentOrders(string symbol){\\n\\t//--- ポジションの数を0で初期化（買、売）\\n\\tint buys=0,sells=0;\\n\\n\\t//--- 全ての保有中＆待機中のポジションを検索\\n\\tfor(int i=0;i< OrdersTotal();i++){\\n\\t\\t//---　ポジションを選択出来なければループを抜ける\\n\\t\\tif(OrderSelect(i,SELECT_BY_POS,MODE_TRADES)==false) break;\\n\\t\\t//--- 注文時の通貨ペアとマジックナンバーを検証\\n\\t\\tif(OrderSymbol()==Symbol() && OrderMagicNumber()==MAGICMA){\\n\\t\\t\\t//--- ポジションが買ポジションならばbuysに+1\\n\\t\\t\\tif(OrderType()==OP_BUY)  buys++;\\n\\t\\t\\t//--- ポジションが売りポジションならばsellsに+1\\n\\t\\t\\tif(OrderType()==OP_SELL) sells++;\\n\\t\\t}\\n\\t}//ループ終了\\n\\t\\n\\t//--- ポジションの数を返す\\n\\tif(buys>0) return(buys);   //--- 買いポジションの数\\n\\telse       return(-sells); //--- 売りポジションの数(-をつけて返す)\\n}\\n//+------------------------------------------------------------------+\\n//| ロットの計算                                                        |\\n//+------------------------------------------------------------------+\\ndouble LotsOptimized(){\\n\\tdouble lot=Lots;\\n\\tint    orders=HistoryTotal();     // 全ポジション履歴\\n\\tint    losses=0;                  // 負数を入れる変数（0で初期化）\\n\\t//--- 余剰証拠金×リスク％÷1000の答えを少数点第１位に丸める\\n\\tlot=NormalizeDouble(AccountFreeMargin()*MaximumRisk/1000.0,1);\\n\\t//--- ロットの減少調整数値がが０以上ならば\\n\\tif(DecreaseFactor>0){\\n\\t\\tfor(int i=orders-1;i>=0;i--){\\n\\t\\t\\t//--- ポジションの履歴がない場合ループを抜ける\\n\\t\\t\\tif(OrderSelect(i,SELECT_BY_POS,MODE_HISTORY)==false){\\n\\t\\t\\t\\tPrint(\\"Error in history!\\");\\n\\t\\t\\t\\tbreak;\\n\\t\\t\\t}\\n\\t\\t\\t\\n\\t\\t\\t//--- 注文時の通貨ペアと開いて選択している通貨ペアが違う\\n\\t\\t\\t//--- 又は\\n\\t\\t\\t//--- 保留中の注文の削除履歴の場合。次へ\\n\\t\\t\\tif(OrderSymbol()!=Symbol() || OrderType()>OP_SELL) continue;\\n\\t\\t\\t\\n\\t\\t\\t//---　利益が出ていたらループを抜ける\\n\\t\\t\\tif(OrderProfit()>0) break;\\n\\t\\t\\t//---　損失ならlossesに+1\\n\\t\\t\\tif(OrderProfit()<0) losses++;\\n\\t\\t}//ループ終了\\n\\t\\t\\n\\t\\t//---　連敗が1より多ければ\\n\\t\\tif(losses>1){\\n\\t\\t\\t//---　ロットの数を再調整\\n\\t\\t\\tlot=NormalizeDouble(lot-lot*losses/DecreaseFactor,1);\\n\\t\\t}\\n\\t}\\n\\t//--- ロット数が0.1未満なら0.1をロットにする\\n\\tif(lot<0.1) lot=0.1;\\n\\t//---　ロット数を返す\\n\\treturn(lot);\\n}\\n//+------------------------------------------------------------------+\\n//| エントリー関数                                                      |\\n//+------------------------------------------------------------------+\\nvoid CheckForOpen(){\\n\\t//---　移動平均線の値を格納する変数を宣言\\n\\tdouble ma;\\n\\t//---　注文の返り値を入れる変数を宣言\\n\\tint    res;\\n\\t\\n\\t//--- 現在の出来高が1より大きければ処理終了\\n\\tif(Volume[0]>1) return;\\n\\t\\n\\t//--- 移動平均線の値を取得\\n\\tma=iMA(NULL,0,MovingPeriod,MovingShift,MODE_SMA,PRICE_CLOSE,0);\\n\\t\\n\\t//--- 売りのエントリー条件\\n\\tif(Open[1]>ma && Close[1]< ma){\\n\\t\\t//--- エントリー      \\n\\t\\tres=OrderSend(Symbol(),OP_SELL,LotsOptimized(),Bid,3,0,0,\\"\\",MAGICMA,0,Red);\\n\\t\\treturn;\\n\\t}\\n\\t//--- 買いのエントリー条件\\n\\tif(Open[1]< ma && Close[1]>ma){\\n\\t\\t//--- エントリー\\n\\t\\tres=OrderSend(Symbol(),OP_BUY,LotsOptimized(),Ask,3,0,0,\\"\\",MAGICMA,0,Blue);\\n\\t\\treturn;\\n\\t}\\n}\\n//+------------------------------------------------------------------+\\n//| クローズ関数                                                        |\\n//+------------------------------------------------------------------+\\nvoid CheckForClose(){\\n\\t//移動平均線の値を入れる変数を宣言\\n\\tdouble ma;\\n\\t//--- 現在の出来高が1より大き場合は処理終了\\n\\tif(Volume[0]>1) return;\\n\\t\\n\\t//--- 移動平均線の値を取得\\n\\tma=iMA(NULL,0,MovingPeriod,MovingShift,MODE_SMA,PRICE_CLOSE,0);\\n\\t\\n\\t//--- 全ての保有中＆待機中のポジションを検索\\n\\tfor(int i=0;i< OrdersTotal();i++){\\n\\t\\t//--- ポジションを選択できない場合ループを抜ける\\n\\t\\tif(OrderSelect(i,SELECT_BY_POS,MODE_TRADES)==false) break;\\n\\t\\t\\n\\t\\t//--- 注文時の通貨ペアとマジックナンバーが一致していない場合次へ\\n\\t\\tif(OrderMagicNumber()!=MAGICMA || OrderSymbol()!=Symbol()) continue;\\n\\t\\t\\n\\t\\t//--- 買ポジションなら\\n\\t\\tif(OrderType()==OP_BUY){\\n\\t\\t\\t//--- 決済条件\\n\\t\\t\\tif(Open[1]>ma && Close[1]< ma){\\n\\t\\t\\t\\t//--- 決済処理\\n\\t\\t\\t\\tif(!OrderClose(OrderTicket(),OrderLots(),Bid,3,White)){\\n\\t\\t\\t\\t\\t//--- 決済に失敗した場合にエラーを吐く\\n\\t\\t\\t\\t\\tPrint(\\"OrderClose error \\",GetLastError());\\n\\t\\t\\t\\t}\\n\\t\\t\\t}\\n\\t\\t\\tbreak;\\n\\t\\t}\\n\\t\\t//--- 売ポジションなら\\n\\t\\tif(OrderType()==OP_SELL){\\n\\t\\t\\t//--- 決済条件\\n\\t\\t\\tif(Open[1]< ma && Close[1]>ma){\\n\\t\\t\\t\\t//--- 決済処理\\n\\t\\t\\t\\tif(!OrderClose(OrderTicket(),OrderLots(),Ask,3,White)){\\n\\t\\t\\t\\t\\t//--- 決済に失敗ならエラーを吐く\\n\\t\\t\\t\\t\\tPrint(\\"OrderClose error \\",GetLastError());\\n\\t\\t\\t\\t}\\n\\t\\t\\t}\\n\\t\\t\\tbreak;\\n\\t\\t}\\n\\t}//ループ終了\\n}\\n//+------------------------------------------------------------------+\\n//| OnTick function                                                  |\\n//+------------------------------------------------------------------+\\nvoid OnTick(){\\n//--- バーの数が100未満又は、自動売買が許可されていない場合処理終了\\n\\tif(Bars< 100 || IsTradeAllowed()==false) return;\\n\\t\\n\\t//--- ポジションを保有していない場合はエントリー関数を呼ぶ\\n\\tif(CalculateCurrentOrders(Symbol())==0){\\n\\t\\tCheckForOpen();\\n\\t//--- ポジションを保有してたらクローズ関数を呼ぶ\\n\\t}else{                                    \\n\\t\\tCheckForClose();\\n\\t} \\n}\\n//+------------------------------------------------------------------+","metadata":{"language":"cpp"}}]', null), ('9ae1290e-2db8-4ef7-b632-b1bce96ef2b5', 'Currency Strength Chart', '通貨強弱', 'fx', 'トレードサポート', '2024-12-30 02:34:39.207226+00', '2024-12-30 02:34:39.207226+00', '', 'currency-strength-chart', null, null), ('9c5150d7-555e-46d2-a8fb-63408f462569', 'ボリンジャーバンドシステム', 'ボリンジャーバンドシステム', 'system', 'EA6(ボリンジャーバンドシステム)', '2025-01-04 20:38:48.703822+00', '2025-01-04 20:38:48.703822+00', '', '-15', '[{"type":"code","content":"\\n// マジックナンバーの定義\\n#define MAGIC 3986\\n\\n// パラメーターの設定//\\nextern int BandsPeriod = 20; // ボリンジャーバンドの期間設定\\nextern int BandsShift = 0; // ボリンジャーバンドを右にシフトする設定\\nextern double BandsDeviations = 2.0; // 標準偏差の設定\\n\\nextern double Lots = 1.0; // 取引ロット数\\nextern int Slip = 10; // 許容スリッページ数\\nextern string Comments = \\" \\"; // コメント\\n\\n// 変数の設定//\\nint Ticket_L = 0; // 買い注文の結果をキャッチする変数\\nint Ticket_S = 0; // 売り注文の結果をキャッチする変数\\nint Exit_L = 0; // 買いポジションの決済注文の結果をキャッチする変数\\nint Exit_S = 0; // 売りポジションの決済注文の結果をキャッチする変数\\n\\n\\nint start()\\n{\\n\\n   // 買いポジションのエグジット\\n   if(   iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,1,2) >= Close[2]\\n      && iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,1,1) < Close[1]\\n      && ( Ticket_L != 0 && Ticket_L != -1 ))\\n      {\\n         Exit_L = OrderClose(Ticket_L,Lots,Bid,Slip,Red);\\n         if( Exit_L == 1 ) {Ticket_L = 0;}\\n      }\\n      \\n   // 売りポジションのエグジット\\n   if(   iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,2,2) <= Close[2]\\n      && iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,2,1) > Close[1]\\n      && ( Ticket_S != 0 && Ticket_S != -1 ))\\n      {\\n         Exit_S = OrderClose(Ticket_S,Lots,Ask,Slip,Blue);\\n         if( Exit_S == 1 ) {Ticket_S = 0;}\\n      }\\n      \\n   // 買いエントリー\\n   if(   iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,2,2) <= Close[2]\\n      && iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,2,1) > Close[1]\\n      && ( Ticket_L == 0 || Ticket_L == -1 )\\n      && ( Ticket_S == 0 || Ticket_S == -1 ))\\n      {\\n         Ticket_L = OrderSend(Symbol(),OP_BUY,Lots,Ask,Slip,0,0, Comments,MAGIC,0,Red);\\n      }\\n      \\n   // 売りエントリー\\n   if(   iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,1,2) >= Close[2]\\n      && iCustom(NULL,0,\\"Bands\\",BandsPeriod,BandsShift,BandsDeviations,1,1) < Close[1]\\n      && ( Ticket_S == 0 || Ticket_S == -1 )\\n      && ( Ticket_L == 0 || Ticket_L == -1 ))\\n      {\\n         Ticket_S = OrderSend(Symbol(),OP_SELL,Lots,Bid,Slip,0,0,Comments,MAGIC,0,Blue);\\n      }\\n      \\nreturn(0);\\n}","metadata":{"language":"cpp"}}]', null), ('9cc90d8b-7bff-4891-b760-11ba768d1e01', 'さ', '景気好調→長期債利回り上昇(買う人がいなくなる)
