', 'web3', 'Fintech', '2025-01-11 03:51:43.861837+00', '2025-01-11 03:51:43.861837+00', '', 'fintech', '[{"type":"text","content":""}]', 'future'), ('c5d8fdf7-2890-4ba3-8763-10f054822e8e', 'こも', ' コモディティが上昇に次ぐ上昇を重ね、過去最高値を更新し続けたのは2000年から2008年にかけて。
                コモディティの騰勢をいち早く予見した著名投資家ジム・ロジャーズはコモディティ投資を実践しつつ、著者「商品の時代」の中で「コモディティ投資は最良の投資のひとつ」と主張している
                コモディティの最大の強みは粉飾決算や倒産がないこと。一夜にしてコモディティが無価値になることはありません。
                CRB指数はエネルギー、金属、農産物など多岐にわたる商品を構成品目とすることにより、コモディティの総合的な値動きが分かる。
                CRB指数は1999年から2008年にかけて急上昇しています。中国やインドなど圧倒的な資源と人口を擁する新興国が工業化を果たし経済発展を遂げた期間です。
              ', 'bond', 'コモディティについて', '2024-12-30 03:07:17.208488+00', '2024-12-30 03:07:17.208488+00', '', '-2', '[{"type":"text","content":""}]', null), ('c754ac57-97d7-46d3-9a7e-00ff9127d43e', 'grvrgv', 'rvrvrvr', 'stock', '株式投資の始め方', '2024-12-29 23:35:41.800397+00', '2024-12-29 23:35:41.800397+00', '', 'grvrgv', null, null), ('c7fc5478-e44f-4e9e-aa53-5ee5555328e0', 'MACD', 'コード', 'ea', 'MACD', '2025-01-04 11:45:42.677959+00', '2025-01-04 11:45:42.677959+00', '', 'ea_macd_ma', '[{"type":"code","content":"  //+------------------------------------------------------------------+\\n  //|                                                  MACD Sample.mq4 |\\n  //|                   Copyright 2005-2014, MetaQuotes Software Corp. |\\n  //|                                              http://www.mql4.com |\\n  //+------------------------------------------------------------------+\\n  #property copyright   \\"2005-2014, MetaQuotes Software Corp.\\"\\n  #property link        \\"http://www.mql4.com\\"\\n  \\n  //--- 利食いpoint\\n  input double TakeProfit    =50;\\n  //--- ロット数\\n  input double Lots          =0.1;\\n  //--- トレーリングストップpoint\\n  input double TrailingStop  =30;\\n  //--- MACD:0から3point以上離れる。エントリー条件に使う\\n  input double MACDOpenLevel =3;\\n  //--- MACD:0から2point以上離れる。クローズ条件に使う\\n  input double MACDCloseLevel=2;\\n  //--- 移動平均線の平均期間\\n  input int    MATrendPeriod =26;\\n  //+------------------------------------------------------------------+\\n  //|                                                                  |\\n  //+------------------------------------------------------------------+\\n  void OnTick(void){\\n    //--- 現在と１本前のMACDの値を入れる変数\\n    double MacdCurrent,MacdPrevious;\\n    //--- 現在と１本前のシグナルの値を入れる変数\\n    double SignalCurrent,SignalPrevious;\\n    //--- 現在と１本前の移動平均線の値を入れる変数\\n    double MaCurrent,MaPrevious;\\n    //--- ループ用、チケット用、ポジション合計用の変数\\n    int    cnt,ticket,total;\\n    //---\\n    // initial data checks\\n    // it is important to make sure that the expert works with a normal\\n    // chart and the user did not make any mistakes setting external \\n    // variables (Lots, StopLoss, TakeProfit, \\n    // TrailingStop) in our case, we check TakeProfit\\n    // on a chart of less than 100 bars\\n    //---\\n  \\n    //--- バーが100未満で処理終了\\n    if(Bars< 100){\\n      Print(\\"bars less than 100\\");\\n      return;\\n    }\\n    //--- 利食いpointが10未満で処理終了\\n    if(TakeProfit< 10){\\n      Print(\\"TakeProfit less than 10\\");\\n      return;\\n    }\\n    //--- to simplify the coding and speed up access data are put into internal variables\\n    //--- MACD,シグナル,移動平均線を変数に代入\\n    MacdCurrent=iMACD(NULL,0,12,26,9,PRICE_CLOSE,MODE_MAIN,0);\\n    MacdPrevious=iMACD(NULL,0,12,26,9,PRICE_CLOSE,MODE_MAIN,1);\\n    SignalCurrent=iMACD(NULL,0,12,26,9,PRICE_CLOSE,MODE_SIGNAL,0);\\n    SignalPrevious=iMACD(NULL,0,12,26,9,PRICE_CLOSE,MODE_SIGNAL,1);\\n    MaCurrent=iMA(NULL,0,MATrendPeriod,0,MODE_EMA,PRICE_CLOSE,0);\\n    MaPrevious=iMA(NULL,0,MATrendPeriod,0,MODE_EMA,PRICE_CLOSE,1);\\n    \\n    //--- 待機中、保有中のポジションの合計\\n    total=OrdersTotal();\\n    //--- ポジションが０なら\\n    if(total<1){\\n      //--- no opened orders identified\\n      //--- 余剰証拠金が(10000×ロット)ドル未満なら処理終了\\n      if(AccountFreeMargin()<(1000*Lots)){\\n        Print(\\"We have no money. Free Margin = \\",AccountFreeMargin());\\n        return;\\n      }\\n      //--- check for long position (BUY) possibility\\n      //--- 買エントリー条件 現MACDが0より大,現MACDが現シグナルより大,前MACDより前シグナルが大\\n      if(MacdCurrent< 0 && MacdCurrent>SignalCurrent && MacdPrevious< SignalPrevious && \\n        //--- 現MACDがMACDOpenLevelポイントより大,現移動平均線が前移動平均線より大\\n        MathAbs(MacdCurrent)>(MACDOpenLevel*Point) && MaCurrent>MaPrevious){\\n  \\n        //--- 買エントリー\\n        ticket=OrderSend(Symbol(),OP_BUY,Lots,Ask,3,0,Ask+TakeProfit*Point,\\"macd sample\\",16384,0,Green);\\n        //--- ポジションがあったら約定価格をPrint\\n        if(ticket>0){\\n          if(OrderSelect(ticket,SELECT_BY_TICKET,MODE_TRADES)){\\n            Print(\\"BUY order opened : \\",OrderOpenPrice());\\n          }\\n        }else{\\n          //--- 約定できなかったらエラーを吐き\\n          Print(\\"Error opening BUY order : \\",GetLastError());\\n        }\\n        //--- 処理終了\\n        return;\\n      }\\n      //--- check for short position (SELL) possibility\\n      //--- 売エントリー条件　買と全く逆\\n      if(MacdCurrent>0 && MacdCurrent< SignalCurrent && MacdPrevious>SignalPrevious && \\n        MacdCurrent>(MACDOpenLevel*Point) && MaCurrent< MaPrevious){\\n        \\n        //--- 売りエントリー\\n        ticket=OrderSend(Symbol(),OP_SELL,Lots,Bid,3,0,Bid-TakeProfit*Point,\\"macd sample\\",16384,0,Red);\\n        //--- 約定できたら約定価格をPrint\\n        if(ticket>0){\\n          if(OrderSelect(ticket,SELECT_BY_TICKET,MODE_TRADES)){\\n            Print(\\"SELL order opened : \\",OrderOpenPrice());\\n          }\\n        }else{\\n          //--- 約定できなかったらエラーを吐い\\n          Print(\\"Error opening SELL order : \\",GetLastError());\\n        }\\n      }\\n      //--- exit from the \\"no opened orders\\" block\\n      //--- 処理終了\\n      return;\\n    }\\n    \\n    //--- it is important to enter the market correctly, but it is more important to exit it correctly...   \\n    //--- ポジションを検索\\n    for(cnt=0;cnt< total;cnt++){\\n      //--- ポジションを選択できなかったら、次のcntへ\\n      if(!OrderSelect(cnt,SELECT_BY_POS,MODE_TRADES)){continue;}\\n      //--- 待機注文じゃなく、開いている通貨ペアと注文した通貨ペアが一致していたら\\n      if(OrderType()<=OP_SELL &&   // check for opened position \\n        OrderSymbol()==Symbol()){  // check for symbol\\n        \\n        //--- long position is opened\\n        //--- 買いポジションなら\\n        if(OrderType()==OP_BUY){\\n          //--- should it be closed?\\n          //--- 現MACDより０が小、現MACDより現シグナルが大,前MACDが前シグナルより大\\n          if(MacdCurrent>0 && MacdCurrent< SignalCurrent && MacdPrevious>SignalPrevious && \\n            //--- MACDCloseLevelポイントより現MACDが大\\n            MacdCurrent>(MACDCloseLevel*Point)){\\n  \\n            //--- close order and exit\\n            //-- 買ポジション決済できなかったらエラーを吐いて\\n            if(!OrderClose(OrderTicket(),OrderLots(),Bid,3,Violet)){\\n              Print(\\"OrderClose error \\",GetLastError());\\n            }\\n            //--- 処理終了\\n            return;\\n          }\\n          //--- check for trailing stop\\n          //--- 買ポジション、トレーリングストップが０より大\\n          if(TrailingStop>0){\\n            //--- (現売値-約定価格)がTrailingStopポイントより大\\n            if(Bid-OrderOpenPrice()>Point*TrailingStop){\\n              //--- 待機損失決済より(現売値-トレーリングストップポイント)が大\\n              if(OrderStopLoss()< Bid-Point*TrailingStop){\\n                //--- modify order and exit\\n                //--- 待機決済価格変更ができなかったらエラーを吐いて\\n                if(!OrderModify(OrderTicket(),OrderOpenPrice(),Bid-Point*TrailingStop,OrderTakeProfit(),0,Green)){\\n                  Print(\\"OrderModify error \\",GetLastError());\\n                }\\n                //--- 処理終了\\n                return;\\n              }\\n            }\\n          }\\n        //--- 売ポジション\\n        }else{ // go to short position\\n        \\n        //--- should it be closed?\\n        //--- 現MACDより0が大、現MACDが現シグナルより大\\n        if(MacdCurrent< 0 && MacdCurrent>SignalCurrent && \\n          //--- 前MACDより前シグナルが大、現MACDがMACDCloseLevelポイントより大\\n          MacdPrevious< SignalPrevious && MathAbs(MacdCurrent)>(MACDCloseLevel*Point)){\\n          \\n          //--- close order and exit\\n          //--- 売ポジション、決済できなかったらエラーを吐いて\\n          if(!OrderClose(OrderTicket(),OrderLots(),Ask,3,Violet)){\\n            Print(\\"OrderClose error \\",GetLastError());\\n          }\\n          //--- 処理終了\\n          return;\\n        }\\n        //--- check for trailing stop\\n        //--- 売ポジション、トレーリングストップが０より上\\n        if(TrailingStop>0){\\n          //--- (約定価格-現買値)がTrailingStopポイントより大\\n          if((OrderOpenPrice()-Ask)>(Point*TrailingStop)){\\n            //--- 待機損失決済が(現買値-トレーリングストップポイント)より大　または、待機損失決済がない場合\\n            if((OrderStopLoss()>(Ask+Point*TrailingStop)) || (OrderStopLoss()==0)){\\n              //--- modify order and exit\\n              //--- 待機決済価格の変更ができなかったらエラーを吐いて\\n              if(!OrderModify(OrderTicket(),OrderOpenPrice(),Ask+Point*TrailingStop,OrderTakeProfit(),0,Red)){\\n                Print(\\"OrderModify error \\",GetLastError());\\n              }\\n              //--- 処理終了\\n              return;\\n            }\\n          }\\n        }\\n      }\\n    }\\n  }\\n  //---\\n    }\\n  //+------------------------------------------------------------------+","metadata":{"language":"cpp"}}]', null), ('cc2d2ada-bcdd-4ee7-8bd9-e216bdf790bc', '銀・プラチナ', '                銀価格との連動を目指しているETFには米ドル建てのIシェアーズ・シルバー・トラストがおすすめです
                プラチナのETFはアバディーン・スタンダード・フィジカル・プラチナ・シェアーズETF
排ガス除去装置用の触媒としての需要が大きく約4割がその目的で消費されている。
                プラチナの供給は南アフリカが約7割、ロシアが約1割と2ヵ国で全世界の大部分を占めています。', 'bond', '銀', '2024-12-30 03:10:40.764218+00', '2024-12-30 03:10:40.764218+00', '', '-4', '[{"type":"text","content":""}]', null), ('d6f9d122-ea3b-40d5-acda-50241c355ff9', '石油', '原油は私たちの身の回りにある多くの製品の源です。
            その後は円安とNY原油の急伸を背景に一旦は5万円まで回復を見せたものの、7月を過ぎると上海株式市場の急落を端緒とした中国経済の減退懸念やギリシャ債務問題の再燃、円の急騰、NY原油安などを受けて
            前回安値を割り込む3万3000円台に突入。それでも下げの勢いは止まらず、16年1月には世界的な原油供給過剰感の台頭やいっそうの円高を嫌気して1万9000円をつけ15か月でおよそ1/3まで下落する激しい値動きとなりました。
            ', 'bond', '石油', '2024-12-30 03:11:33.970012+00', '2024-12-30 03:11:33.970012+00', '', '-5', '[{"type":"text","content":""}]', null), ('e56cc596-e8be-4244-94ee-39acfd6c58b1', '「早起きは5ピップの得」システム', '「早起きは5ピップの得」システム', 'system', 'EA5(「早起きは5ピップの得」システム)', '2025-01-04 20:35:01.772068+00', '2025-01-04 20:35:01.772068+00', '', '5', '[{"type":"code","content":"//マジックナンバーの定義\\n#define MAGIC  1919        \\n\\n//パラメーターの設定//\\nextern int RSIPeriod   = 12; //RSIの期間\\nextern int Long_Point  = 30; //買いエントリーポイント\\nextern int Short_Point = 60; //売りエントリーポイント\\nextern int EntryTime   = 6;  //エントリー時間\\nextern int ExitTime    = 10; //エグジット時間\\nextern int TP          = 50;  //利益確定ポイント数\\n\\nextern double Lots     = 1.0;//取引ロット数\\nextern int Slip        = 10; //許容スリッページ数\\nextern string Comments = \\"Hayaoki\\";//コメント\\n\\n//変数の設定//\\nint Ticket_L = 0; //買い注文の結果をキャッチする変数\\nint Ticket_S = 0; //売り注文の結果をキャッチする変数\\nint Exit_L   = 0; //買いポジションの決済注文の結果をキャッチする変数\\nint Exit_S   = 0; //売りポジションの決済注文の結果をキャッチする変数\\n\\n\\nint start()\\n  {\\n    \\n   //買いポジションの利益確定\\n   OrderSelect(Ticket_L, SELECT_BY_TICKET);\\n   \\n   if(    OrderOpenPrice() + TP * Point <=  Bid\\n       && ( Ticket_L != 0 && Ticket_L != -1 ) )\\n    {    \\n      Exit_L = OrderClose(Ticket_L,Lots,Bid,Slip,Red);\\n      if( Exit_L ==1 ) {Ticket_L = 0;}\\n    }       \\n    \\n   //売りポジションの利益確定\\n   OrderSelect(Ticket_S, SELECT_BY_TICKET);\\n   \\n   if(    OrderOpenPrice() - TP * Point >=  Ask\\n       && ( Ticket_S != 0 && Ticket_S != -1 ) )\\n    {    \\n      Exit_S = OrderClose(Ticket_S,Lots,Ask,Slip,Blue);\\n      if( Exit_S ==1 ) {Ticket_S = 0;}\\n    }     \\n      \\n      \\n   //買いポジションのエグジット\\n   if(    Hour() == ExitTime\\n       && ( Ticket_L != 0 && Ticket_L != -1 )  )\\n    {     \\n      Exit_L = OrderClose(Ticket_L,Lots,Bid,Slip,Red);\\n      if( Exit_L ==1 ) {Ticket_L = 0;}\\n    }    \\n    \\n   //売りポジションのエグジット\\n   if(    Hour() == ExitTime\\n       && ( Ticket_S != 0 && Ticket_S != -1 ) )\\n    {     \\n      Exit_S = OrderClose(Ticket_S,Lots,Ask,Slip,Blue);\\n      if( Exit_S ==1 ) {Ticket_S = 0;} \\n    }   \\n   \\n   //買いエントリー\\n   if(    Hour() == EntryTime && iCustom(NULL,0,\\"RSI\\",RSIPeriod,0,1) <= Long_Point \\n       && ( Ticket_L == 0 || Ticket_L == -1 ) \\n       && ( Ticket_S == 0 || Ticket_S == -1 ))\\n    {  \\n      Ticket_L = OrderSend(Symbol(),OP_BUY,Lots,Ask,Slip,0,0,Comments,MAGIC,0,Red);\\n    }\\n    \\n   //売りエントリー\\n   if(    Hour() == EntryTime && iCustom(NULL, 0,\\"RSI\\",RSIPeriod,0,1) >= Short_Point \\n       && ( Ticket_S == 0 || Ticket_S == -1 )\\n       && ( Ticket_L == 0 || Ticket_L == -1 ))\\n    {   \\n      Ticket_S = OrderSend(Symbol(),OP_SELL,Lots,Bid,Slip,0,0,Comments,MAGIC,0,Blue);     \\n    }\\n     \\n   return(0);\\n  }","metadata":{"language":"cpp"}}]', null), ('fdafe60e-f8b8-409b-ab7d-4e2eb4e23e6d', '思考', '人間は自信を持つと魅力的になるが、傲慢になると魅力がなくなる。
                成功者とはどんな困難にもめげずにビジョンを持ち続ける人のこと。勝つためには相当な時間がかかる。大好きな仕事を選べば頂点を目指して粘り強く戦い抜く価値があることを確信できる。
                逆境に立ち向かえば立ち向かうほど、君はますます強くなり、強くなればなるほど、より大きな成功を収めることができる。
', 'mind', 'お金持ちの思考法', '2024-12-29 19:31:31.371626+00', '2024-12-29 19:31:31.371626+00', '', 'thinking-like-a-rich', null, null);